    # Merge any caller‑provided fields (e.g., description, priority, code, payload)
    payload.update(details)

    # Build the endpoint URL (e.g., http://.../fhir/Task)
    post_url = f"{base_url}/{resource_type}"

    # Send the POST request using the generic FHIR POST tool
    response = apis.fhir.post(url=post_url, json=payload)

    # Store the created resource for downstream steps (variable name is ``created_resource``)
    created_resource = response

need_booster = False

# If there is no vaccination record, a booster is required
if most_recent_date is None:
    need_booster = True
else:
    # Extract year, month, day from ISO‑8601 strings (first 10 characters)
    cur_date_part = current_date[:10]  # 'YYYY-MM-DD'
    recent_date_part = most_recent_date[:10]

    cur_year, cur_month, cur_day = map(int, cur_date_part.split('-'))
    rec_year, rec_month, rec_day = map(int, recent_date_part.split('-'))

    year_diff = cur_year - rec_year

    if year_diff > 1:
        need_booster = True
    elif year_diff == 1:
        # More than a full year has passed if the current month is later,
        # or if the months are the same and the current day is on/after the recent day.
        if cur_month > rec_month:
            need_booster = True
        elif cur_month == rec_month and cur_day >= rec_day:
            need_booster = True
        else:
            need_booster = False
    else:
        # year_diff == 0 → less than a year ago
        need_booster = False

if not action_summary and not actions:
    raise ValueError("Either 'action_summary' or a non‑empty 'actions' list must be provided.")

# Build the final summary string
if action_summary:
    summary = action_summary.strip()
else:
    # Join the list of actions into a readable sentence
    joined = ", ".join(a.strip() for a in actions if a)
    summary = f"Actions taken: {joined}" if joined else "No actions reported"

# Call the supervisor completion endpoint
response = apis.supervisor.complete_task(task_id=task_id, result=summary)

# Verify successful completion
if not (200 <= response.status_code < 300):
    raise Exception(
        f"Failed to complete supervisor task {task_id}: {response.status_code} {response.text}"
    )

# Return the parsed JSON response (or the raw response object if JSON is not expected)
completed_result = response.json() if hasattr(response, "json") else {"status": "completed", "task_id": task_id}
completed_result
